import json
import os
import subprocess
import config

class InstructorAgent:
    def __init__(self):
        self.profile = self.load_profile()
        self.lesson = None
        self.sandbox_path = os.path.abspath(config.SANDBOX_DIR)

        if not os.path.exists(self.sandbox_path):
            os.makedirs(self.sandbox_path)

    def load_profile(self):
        """Loads the vulnerability profile from the Oracle."""
        if os.path.exists(config.JSON_PROFILE):
            with open(config.JSON_PROFILE, "r") as f:
                return json.load(f)
        return {}

    def get_lesson_hint(self, lesson_num, stage="discovery"):
        """Returns a Socratic hint based on the Oracle's data."""
        lesson_data = self.profile.get(str(lesson_num))
        if not lesson_data:
            return "The Oracle has no data for this lesson. Run a scan first!"

        hints = {
            "discovery": f"Look at how the page handles input. If you try to 'break' the query with a single quote ('), what happens? Does the response change?",
            "structure": f"The page is reflecting data. Try to find the number of columns using 'ORDER BY'.",
            "extraction": f"You've found {lesson_data.get('extra', 'some')} columns. Use a UNION SELECT with placeholders like '1,2,3' to see where data is reflected."
        }
        return hints.get(stage, "Keep exploring!")

    def verify_payload_in_sandbox(self, url, payload):
        """
        Agentic Feature: Executes a student's payload in a safe sandbox.
        Uses curl to check for signs of successful injection.
        """
        # Security: Simple command construction in sandbox
        cmd = ["curl", "-s", f"{url}{payload}"]

        # Only allow permitted commands (though we hardcode curl here)
        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=5)
            return {
                "length": len(result.stdout),
                "success": any(marker in result.stdout for marker in ["security", "admin", "Dumb"]),
                "output_sample": result.stdout[:200]
            }
        except Exception as e:
            return {"error": str(e)}

    def give_feedback(self, lesson_num, user_payload):
        """Analyzes user payload against the Oracle's key."""
        lesson_data = self.profile.get(str(lesson_num))
        correct_closure = lesson_data.get("closure")

        if correct_closure not in user_payload:
            return f"Close, but look at your syntax. The server is expecting a different closure. Are you using '{correct_closure}'?"

        # Run in sandbox
        verification = self.verify_payload_in_sandbox(f"http://172.17.59.5/sqli/Less-{lesson_num}/?id=", user_payload)

        if verification.get("success"):
            return "Excellent! Your payload worked and leaked data. What's the next step for full database extraction?"
        else:
            return f"Your payload had the right closure, but the server response was {verification['length']} bytes long. It didn't seem to reflect any data. Try using a negative ID (id=-1) to make room for the UNION results."

if __name__ == "__main__":
    # Prototype interaction loop
    agent = InstructorAgent()
    print("Agentic Instructor initialized.")
    print("Oracle Data Loaded for Lessons:", list(agent.profile.keys()))

    # Mocking an interaction for Lesson 1
    print("
[User]: id=1'")
    print(f"[Agent]: {agent.give_feedback(1, "1'")}")

    print("
[User]: id=-1' UNION SELECT 1,2,3-- -")
    print(f"[Agent]: {agent.give_feedback(1, "-1' UNION SELECT 1,2,3-- -")}")

